class Solution(object):
    def distanceTraveled(self, mainTank, additionalTank):
        dist = 0
        used = 0
        while mainTank > 0:
            mainTank -= 1
            used += 1
            dist += 10
            if used % 5 == 0 and additionalTank > 0:
                mainTank += 1
                additionalTank -= 1
        return dist
